def most_common_word(s):
    if not s:
        return ''

    word_count = {}
    for word in s.lower().split():
        word_count[word] = word_count.get(word, 0) + 1

    max_count = max(word_count.values(), default=0)
    common_words = [word for word, count in word_count.items() if count == max_count]

    return min(common_words)

# Edge case: Empty string
print(most_common_word(""))  # Output: ''
